Yes! You can add #[serde(rename = "new_name")] on a struct field and it will appear as that name when serializing to JSON. Example:

#[derive(Serialize, Deserialize)]
struct Config {
    #[serde(rename = "api_key")]
    token: String,
}
let json = serde_json::to_string(&Config { token: "sk-abc123" });
// produces {"token": "sk-abc123"}

